	.SBTTL	ICOCOMM; Commandes; ---------; ***	DEFINE	***; Cette commande est l par compatibilit avec le CLE.DODEFINE:	CLR.W	D7		; D7 <-- ok	RET; ***	CASH	***DOCASH:	FOS	?CASH		; ajoute un prog. dans le cash	JUMP',NE 90$	CALL	SKPNAM		; A3 <-- ^nom suivant	JUMP,EQ	DOCASH		; si existe => DOCASH	CLR.W	D790$:	RET; ***	UNCASH	***DOUNCASH:	FOS	?UNCASH		; enlve un prog. du cash	JUMP',NE 90$	CALL	SKPNAM		; A3 <-- ^nom suivant	JUMP,EQ	DOUNCASH	; si existe => DOUNCASH	CLR.W	D790$:	RET; ***	FORMAT	***DOFORMAT:	CALL	OPESWDO		; ouvre la grande sous-fentre	CALL	USEGCL		; utilise le gencar des listes	LOAD.L	A0,A3		; A0 <-- ^commande	LIB	?GETUPH		; A4 <-- cherche nom physique	JUMP,NE	90$	LOAD.W	D7,#ERUTYP	COMP.B	(A4)+1,#'F	; nom "$F*" ($FLO) ?	JUMP,NE	90$		; non => 90$	LOAD.L	A3,A4		; A3 <-- ^nom physique	LOAD.L	A2,A4		; A2 <-- ^nom physique	INC.L	A3		; saute le "$"	FOS	?UNAMDRIV	; D2 <-- numro du driver	JUMP,NE	90$	DEC.L	A3		; A3 <-- ^sur le "$"	LIB	?AFTIM	.ASCIZ	/Est-ce que la disquette en /	.EVEN	LIB	?AFFILE		; affiche le nom physique	LIB	?AFTIM	.ASCIZ	/ est neuve ? /	.EVEN;;?	.W	LIB,?AFTIM;;?	.ASCIZ	/S'agit-il d'une disquette neuve ? /;;?	.EVEN	LIB	?YESNO		; attend oui/non ...	JUMP,EQ 30$		; oui => 30$				; non =>	LIB	?AFTIM	.ASCIZ	/Voulez-vous vraiment dtruire son contenu ? /	.EVEN;;?	.W	LIB,?AFTIM;;?	.ASCIZ	/Voulez-vous vraiment dtruire le contenu de /;;?	.EVEN;;?	.W	LIB,?AFFILE	; affiche le nom physique;;?	.W	LIB,?AFTIM;;?	.ASCIZ	/ ? /;;?	.EVEN	LIB	?YESNO		; attend oui/non ...	JUMP,EQ 40$		; oui => 40$	JUMP	80$		; non => 80$30$:	LIB	?AFTIM	.B	NOCURS,CR	.ASCIZ	/Formatage physique, attendez un instant .../	.EVEN	LOAD.L	A3,#R16"TXCOMF	; A3 <-- ^commande de formatage	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commandes	LOAD.W	D4,#LBUCOM	; D4 <-- lg max du buffer	LIB	?TRCOMM		; construit la commande	JUMP,NE	90$	LOAD.L	A3,A2		; A3 <-- ^nom physique	LOAD.W	D1,#2^15	; D1 <-- type inconnu et pas de question	LIB	?SNCOMM		; envoie la commande de formatage	JUMP,NE	90$		; erreur => 90$40$:	LIB	?AFTIM	.B	NOCURS,CR	.ASCIZ	/Formatage software, attendez un instant .../	.EVEN	LOAD.L	A3,A0		; A3 <-- ^commande	LOAD.W	D4,#31		; D4 <-- hachage par dfaut	CALL	SKPNAM		; A3 <-- ^nombre	JUMP',NE 60$		; pas de nombre => 60$	CALL	GETNUM		; D4 <-- valeur de hachage60$:	LOAD.W	D7,#ERSYNT	TEST.W	D4		; valeur de hachage nulle ?	JUMP',EQ 90$		; oui => 90$	LOAD.L	A3,A0		; A3 <-- ^nom logique	LOAD.L	A4,#0		; A4 <-- ^liste des bads blocs	FOS	?FORMAT		; formatage soft ...	JUMP',NE 90$80$:	CLR.W	D7		; D7 <-- ok90$:	RET; ***	COMMAND	***DOCOMMAND:	CALL	OPESWDO		; ouvre la grande sous-fentre	CALL	USEGCL		; utilise le gencar des listes	LIB	?GTCOMM		; cherche type selon switch	LOAD.W	D1,D3		; D1 <-- type du driver	LOAD.L	A2,A3	LIB	?GETUPH		; A4 <-- cherche nom physique	JUMP',NE 90$	LOAD.L	A3,A4		; A3 <-- ^nom physique	INC.L	A3		; saute le "$"	FOS	?UNAMDRIV	; D2 <-- numro du driver	JUMP',NE 90$	LOAD.L	A3,A2		; A3 <-- ^ds ligne de commande	LOAD.L	A2,A4		; A2 <-- ^nom physique	CALL	SKPNAM		; A3 <-- ^paramtres ASCII	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commandes	LOAD.W	D4,#LBUCOM	; D4 <-- lg max du buffer	LIB	?TRCOMM		; construit la commande	JUMP',NE 90$	LOAD.L	A3,A2		; A3 <-- ^nom physique	LIB	?SNCOMM		; envoie la commande90$:	RET; ***	HALT	***DOHALT:	LIB	?GETUPH		; A4 <-- cherche nom physique	JUMP',NE 90$	LOAD.L	A3,A4		; A3 <-- ^nom physique	INC.L	A3		; saute le "$"	FOS	?UNAMDRIV	; D2 <-- numro du driver	JUMP',NE 90$	BIOS	?DAVOTR		; avorte transfert90$:	RET; ***	ENTER	***DOENTER:	FOS	?ENTER	RET; ***	RELEASE	***DORELEASE:	FOS	?RELEASE	RET; ***	DIR	***DODIR:	FOS	?DIR	RET; ***	REL	***DOREL:	FOS	?REL	RET; ***	INSTALL	***DOINSTALL:	LOAD.B	D0,D3		; D0 <-- switch ventuel	LOAD.L	A2,A3		; A2 <-- ^nom logique (#...)	CALL	SKPNAM	LOAD.L	A1,A3		; A1 <-- ^nom physique ($...)	CALL	SKPNAM		; A3 <-- ^paramtres v.	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^buffer pour commandes	LOAD.W	D4,#LBUCOM	; D4 <-- lg max du buffer	LIB	?TRCOMM		; construit les paramtres	JUMP',NE 90$	LOAD.L	A3,A2		; A3 <-- ^nom logique (#...)	LOAD.L	A2,A4		; A2 <-- ^paramtre(s)	LOAD.L	A4,A1		; A4 <-- ^nom physique ($...)	COMP.B	(A3),#'-	; nom logique = "-" ou "*" ?	JUMP',EQ 10$		; oui => 10$	COMP.B	(A3),#'*	; non => 15$	JUMP',NE 15$10$:	LOAD.L	A3,#0		; A4 <-- pas de nom logique15$:	CLR.L	D3		; D3 <-- numro pour tous	COMP.B	D0,#'V		; INSTALL/V ?	JUMP',NE 40$		; non => 40$	TSET.L	D3:#BIVIRTUEL	; oui => install virtuel40$:	FOS	?VINSTALL	; fait INSTALL virtuel ou pas90$:	RET; ***	DEINSTALL ***DODEINSTALL:	CLR.L	D3		; D3 <-- numro pour tous	FOS	?DEINSTALL	RET; ***	ASSIGN	***DOASSIGN:	PUSH.L	A3	CALL	SKPNAM	LOAD.L	A4,A3		; A4 <-- ^nom physique ($...)	POP.L	A3		; A3 <-- ^nom logique (#...)	CLR.W	D3		; D3 <-- numro pour tous	FOS	?ASSIGN	RET; ***	DEASSIGN ***DODEASSIGN:	CLR.W	D3		; D3 <-- numro pour tous	FOS	?DEASSIGN	RET; ***	ASSGC	***DOASSGC:	LOAD.L	A4,#(A6)+OBUCOM	; A4 <-- ^pour commande	LOAD.B	(A4+),#ASSGC	; <ASSGC>	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 90$	LOAD.B	(A4+),D3	; <fonte> logique	LOAD.B	(A4+),D4	; <style> logique	LOAD.B	(A4+),D5	; <taille> logique	CLR.B	D3		; supprime l'assignation si	CLR.B	D4		; le nom physique n'existe	CLR.B	D5		; pas dans la commande.	PUSH.W	D3	CALL	SKPNAM		; A3 <-- saute nom logique	POPM.W	D3	JUMP',NE 50$		; si n'existe pas => 50$	LIB	?SYNGC		; D3,D4,D5 <-- fst	JUMP',NE 90$50$:	LOAD.B	(A4+),D3	; <fonte> physique	LOAD.B	(A4+),D4	; <style> physique	LOAD.B	(A4+),D5	; <taille> physique	LOAD.L	A3,#(A6)+OBUCOM	LOAD.W	D3,#1+3+3	LIB	?STRING		; ajoute/supprime galit90$:	RET; ***	MEMGC	***DOMEMGC:	LOAD.B	D3,#MEMGC	LIB	?AFCAR		; mmorise les ASSGC ...	RET; ***	REP	***DOREP:	LOAD.L	A3,#(A6)+OBUEXE	; A3 <-- ^commande	LIB	?SKPNAM		; A3 <-- ^nom rpertoire	JUMP,NE 70$	PUSH.L	A3	LOAD.L	A3,#R16"RELALL	FOS	?REL		; supprime tout prfixe	POP.L	A3	LOAD.L	A4,#(A6)+OBUREP20$:	LOAD.B	D3,(A3+)	JUMP',EQ 25$	COMP.B	D3,#CR	JUMP',EQ 25$	COMP.B	D3,#'.	JUMP',EQ 25$	COMP.B	D3,#':	JUMP',EQ 25$	COMP.B	D3,#'a	JUMP',LO 23$	COMP.B	D3,#'z	JUMP',HI 23$	SUB.B	D3,#'a-'A	; min --> MAJ23$:	LOAD.B	(A4+),D3	JUMP	20$25$:	LOAD.B	(A4+),#':	CLR.B	(A4)	LOAD.L	A3,#(A6)+OBUREP	; A3 <-- ^rpertoire:	CLR.W	D3		; D3 <-- global	FOS	?LENTER		; entre si pas dj fait	JUMP',EQ 30$	COMP.W	D7,#ERUUSE	JUMP,NE	80$30$:	LOAD.L	A3,#R16"REPADD35$:	LOAD.B	(A4+),(A3+)	; OBUREP <-- rp:,#MM0:	JUMP,NE	35$	LOAD.L	A3,#(A6)+OBUREP	; A3 <-- ^rp:,#MM0:	FOS	?DIR	JUMP',NE 80$	JUMP'	90$70$:	CLR.B	(A6)+OBUREP	; plus de rpertoire	LOAD.L	A3,#R16"RELALL	FOS	?REL		; supprime tout prfixe	CLR.W	D7	JUMP'	90$80$:	CLR.B	(A6)+OBUREP	; plus de rpertoire90$:	RET; ***	MEM	***DOMEM:	CALL	OPESWDO		; ouvre la grande sous-fentre	CALL	USEGCL		; utilise le gencar des listes	GESMEM	?ARGMEM	JUMP,NE 90$	LIB	?AFTIM	.ASCIZ	/Reste: /	.EVEN	LOAD.B	D3,#8	LOAD.B	D2,#2^BAFDCM!2^BAFDSP ; D2 <-- compact + '	LIB	?AFDEC		; affiche en dcimal	LIB	?AFTIM	.ASCIZ	/   Plus grande place: /	.EVEN	LOAD.L	D4,D5	LOAD.B	D3,#8	LOAD.B	D2,#2^BAFDCM!2^BAFDSP ; D2 <-- compact + '	LIB	?AFDEC		; affiche en dcimal	LIB	?AFCR	CALL	GETCAR		; attend une touche ...	CLR.W	D790$:	RET; ***	ABORT	***DOABORT:	TCLR.B	(A6)+OFLAGM:#BMSTOP	LOAD.B	D3,(A3)	LIB	?MINMAJ		; D3 <-- lettre MAJUSCULE	COMP.B	D3,#'O		; oui ?	JUMP',EQ 50$	COMP.B	D3,#'Y		; yes ?	JUMP',EQ 50$	COMP.B	D3,#'J		; ja ?	JUMP',EQ 50$	COMP.B	D3,#'S		; si ?	JUMP',NE 90$50$:	TSET.B	(A6)+OFLAGM:#BMSTOP90$:	CLR.W	D7		; D7 <-- ok	RET; ***	DISPLAY   ***DODISPLAY:	TSET.B	(A6)+OFLAGM:#BMNOAF	LOAD.B	D3,(A3)	LIB	?MINMAJ		; D3 <-- lettre MAJUSCULE	COMP.B	D3,#'O		; oui ?	JUMP',EQ 50$	COMP.B	D3,#'Y		; yes ?	JUMP',EQ 50$	COMP.B	D3,#'J		; ja ?	JUMP',EQ 50$	COMP.B	D3,#'S		; si ?	JUMP',NE 90$50$:	TCLR.B	(A6)+OFLAGM:#BMNOAF90$:	CLR.W	D7		; D7 <-- ok	RET; ***	ARRET	***DOARRET:	CALL	OPESWDO		; ouvre la grande sous-fentre	CALL	USEGCL		; utilise le gencar des listes	LIB	?AFTIM	.ASCIZ	/Voulez-vous vraiment arrter votre Smaky ? /	.EVEN	LIB	?YESNO		; attend oui/non ...	JUMP',EQ DOARRET1	CLR.W	D7	RETDOARRET1:	LOAD.B	D3,#NOCURS	LIB	?AFCAR		; plus de curseur	CLR.W	D3		; D3 <-- global	FOS	?RENTER		; release tous les enter;	JUMP,NE	...	LIB	?BUZZ		; grand bruit	LOAD.L	A3,#R16"TXMENN	LIB	?AFMENU		; plus rien dans les soft keys	CALL	CLOSWDO		; ferme la grande sous-fentre	LIB	?AFTIM	.B	EOP,NOCURS,0	.EVEN	LOAD.W	D3,(A6)+OBUSTD+ODFDY	SR.W	D3,#1	SWAP.W	D3	CLR.W	D3	LIB	?SETCURS	LIB	?AFTIM	.ASCII	/<TAB><TAB><TAB>Enlevez la ou les disquettes<CR>/	.ASCIZ	/<TAB><TAB><TAB>puis coupez le courant .../	.EVEN50$:	LIB	?GETCAR		; attend toujours ...	JUMP	50$;--------\; SKPNAM  >;========/; Saute jusqu'au nom suivant.; in	A3.L	^nom; out	A3.L	^nom suivant;	D7.W	erreur; mod	D7.W, A3.LSKPNAM:	LIB	?SKPNAM	JUMP',EQ 90$20$:	TEST.B	(A3)		; A3 <-- ^terminateur	JUMP',EQ 90$	COMP.B	(A3),#CR	JUMP',EQ 90$	INC.L	A3	JUMP	20$90$:	TEST.W	D7		; retour EQ/NE	RET;--------\; GETNUM  >;========/; Donne un nombre dcimal.; in	A3.L	^nombre dcimal; out	A3.L	^plus loin;	D4.L	nombre;	D7.W	erreur; mod	D4.L, D7.W, A3.LGETNUM:	PUSH.L	D3	CLR.L	D4		; D4 <-- nombre	LOAD.W	D7,#ERSYNT10$:	LOAD.B	D3,(A3)	JUMP',EQ 80$	COMP.B	D3,#CR	JUMP',EQ 80$	COMP.B	D3,#SPACE	JUMP',EQ 80$	COMP.B	D3,#'0	JUMP',LO 90$	COMP.B	D3,#'9	JUMP',HI 90$	INC.L	A3		; A3 <-- ^car suivant	SUB.B	D3,#'0		; D3 <-- 0..9	AND.L	D3,#H'FF	MUL.WU	D4,#10.	ADD.L	D4,D3	JUMP	10$80$:	CLR.W	D7		; D7 <-- ok90$:	POP.L	D3	RET; Table; -----RELALL:	.ASCIZ	"*"		; release gnralREPADD:	.ASCIZ	",#MM0:"	; ajout aprs rep:TXCOMF:	.ASCIZ	"F"		; commande de formatageTACOMM:	.ASCIZ	"*.CLE"	.EVEN	.W	EXMACRO	.ASCIZ	"DEFINE"	.EVEN	.W	DODEFINE	.ASCIZ	"CASH"	.EVEN	.W	DOCASH	.ASCIZ	"CACHE"	.EVEN	.W	DOCASH	.ASCIZ	"UNCASH"	.EVEN	.W	DOUNCASH	.ASCIZ	"UNCACHE"	.EVEN	.W	DOUNCASH	.ASCIZ	"COMMAND"	.EVEN	.W	DOCOMMAND	.ASCIZ	"FORMAT"	.EVEN	.W	DOFORMAT	.ASCIZ	"HALT"	.EVEN	.W	DOHALT	.ASCIZ	"ENTER"	.EVEN	.W	DOENTER	.ASCIZ	"RELEASE"	.EVEN	.W	DORELEASE	.ASCIZ	"INSTALL"	.EVEN	.W	DOINSTALL	.ASCIZ	"DEINSTALL"	.EVEN	.W	DODEINSTALL	.ASCIZ	"ASSIGN"	.EVEN	.W	DOASSIGN	.ASCIZ	"DEASSIGN"	.EVEN	.W	DODEASSIGN	.ASCIZ	"DIR"	.EVEN	.W	DODIR	.ASCIZ	"REL"	.EVEN	.W	DOREL	.ASCIZ	"ASSGC"	.EVEN	.W	DOASSGC	.ASCIZ	"MEMGC"	.EVEN	.W	DOMEMGC	.ASCIZ	"REP"	.EVEN	.W	DOREP	.ASCIZ	"MEM"	.EVEN	.W	DOMEM	.ASCIZ	"ABORT"	.EVEN	.W	DOABORT	.ASCIZ	"DISPLAY"	.EVEN	.W	DODISPLAY	.ASCIZ	"ARRET"	.EVEN	.W	DOARRET	.B	0	.EVEN	.END